  function list(items) {
    return '<ul>' + items.map(function (item) { return '<li>' + item + '</li>'; }).join('') + '</ul>';
  }

  function compare(bad, good) {
    return '<div class="compare-grid"><div class="compare-card bad"><h5>错误做法</h5>' + list(bad) + '</div><div class="compare-card good"><h5>更好做法</h5>' + list(good) + '</div></div>';
  }

  function article(data) {
    var isRich = /^ch2[3-7]$/.test(data.id);
    var html = '';
    if (isRich) {
      html += '<article class="extra-column extra-' + data.id + '">';
      html += '<section class="extra-hero"><div class="extra-hero__eyebrow">' + data.chapterNum + ' · 新增深度专栏</div><h1>' + data.title + '</h1><p>' + data.lead + '</p><div class="extra-hero__stats"><span>诊断</span><span>对照</span><span>场景</span><span>训练</span></div></section>';
      html += '<div class="extra-quicknav"><a href="#principles">底层原则</a><a href="#mistakes">误区对照</a><a href="#actions">实操清单</a><a href="#scenes">场景训练</a><a href="#review">复盘任务</a></div>';
    }
    html += '<p class="lead">' + data.lead + '</p>';
    html += '<div class="box"><strong>本章解决：</strong>' + data.problem + '</div>';
    if (isRich && data.dashboard) html += dashboard(data.dashboard);
    html += '<h2 id="principles">一、底层原则</h2>' + list(data.principles);
    html += '<h2 id="mistakes">二、常见误区与替代动作</h2>' + compare(data.mistakes, data.better);
    html += '<h2 id="actions">三、实操清单</h2>' + list(data.actions);
    html += '<h2 id="scenes">四、典型场景</h2><div class="scene-card"><h3>' + data.sceneTitle + '</h3><p>' + data.scene + '</p></div>';
    html += richExtra(data);
    html += '<h2 id="review">训练任务</h2><div class="template-box"><div class="template-box-title">本周练习</div>' + list(data.training) + '</div>';
    if (data.warning) html += '<div class="box-warning"><strong>边界提醒：</strong>' + data.warning + '</div>';
    if (isRich) html += '</article>';
    return html;
  }

  function dashboard(items) {
    return '<div class="extra-dashboard">' + items.map(function (item) {
      return '<div class="extra-dashboard__card"><strong>' + item[0] + '</strong><span>' + item[1] + '</span></div>';
    }).join('') + '</div>';
  }

