  function practiceList(items) {
    return '<ul>' + items.map(function (item) { return '<li>' + item + '</li>'; }).join('') + '</ul>';
  }

  function practiceCard(item) {
    return '<div class="practice-card"><h3>' + item[0] + '</h3><p>' + item[1] + '</p></div>';
  }

  function practiceScript(title, lines) {
    return '<div class="practice-script-card"><h3>' + title + '</h3>' + lines.map(function (line) { return '<p>' + line + '</p>'; }).join('') + '</div>';
  }

  function practiceScenario(item) {
    return '<div class="practice-case-card"><span>' + item[0] + '</span><h3>' + item[1] + '</h3><p><b>别做：</b>' + item[2] + '</p><p><b>改成：</b>' + item[3] + '</p></div>';
  }

